package armo_builtins

import rego.v1

# Fails is rolebinding/clusterrolebinding gives permissions to anonymous user
deny contains msga if {
	rolebindings := [rolebinding | rolebinding = input[_]; endswith(rolebinding.kind, "Binding")]
	rolebinding := rolebindings[_]
	subject := rolebinding.subjects[i]
	isAnonymous(subject)
	delete_path := sprintf("subjects[%d]", [i])
	msga := {
		"alertMessage": sprintf("the following RoleBinding: %v gives permissions to anonymous users", [rolebinding.metadata.name]),
		"alertScore": 9,
		"deletePaths": [delete_path],
		"failedPaths": [delete_path],
		"packagename": "armo_builtins",
		"alertObject": {"k8sApiObjects": [rolebinding]},
	}
}

isAnonymous(subject) if {
	subject.name == "system:anonymous"
}

isAnonymous(subject) if {
	subject.name == "system:unauthenticated"
}

# regal ignore:directory-package-mismatch
package armo_builtins

import rego.v1

deny contains msga if {
	workload_kinds := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job", "Pod", "CronJob"}
	workload := input[_]
	workload_kinds[workload.kind]

	networkpolicies := [networkpolicy | networkpolicy = input[_]; is_network_policy(networkpolicy)]
	not connected_to_any_network_policy(workload, networkpolicies)

	msga := {
		"alertMessage": sprintf("%v: no networkpolicy configured in labels", [workload.metadata.name]),
		"packagename": "armo_builtins",
		"failedPaths": [],
		"fixPaths": [],
		"alertObject": {"k8sApiObjects": [workload]},
	}
}

# Helper function to identify all network policy types
is_network_policy(policy) if {
	policy.kind == "NetworkPolicy"
}

is_network_policy(policy) if {
	policy.kind == "CiliumNetworkPolicy"
}

is_network_policy(policy) if {
	policy.kind == "CiliumClusterwideNetworkPolicy"
}

# Returns the list of CiliumNetworkPolicySpec entries, unifying the
# `spec:` (single) and `specs:` (list) forms documented for CNP/CCNP CRDs.
# Either field may be present; both is also legal in Cilium.
cilium_policy_specs(policy) := specs if {
	from_spec := [s | s := policy.spec]
	from_specs := object.get(policy, "specs", [])
	specs := array.concat(from_spec, from_specs)
}

connected_to_any_network_policy(workload, networkpolicies) if {
	connected_to_network_policy(workload, networkpolicies[_])
}

# --- Cilium endpointSelector match (shared across pod/workload/cronjob) ---

# matchLabels with keys: every key on the selector must equal the corresponding label.
cilium_endpoint_selector_matches(spec, labels) if {
	count(spec.endpointSelector.matchLabels) > 0
	count({x | spec.endpointSelector.matchLabels[x] == labels[x]}) == count(spec.endpointSelector.matchLabels)
}

# Selects-all: covers `endpointSelector: {}` and `endpointSelector: { matchLabels: {} }`.
# A non-empty matchExpressions makes the selector selective, NOT match-all
# (per Kubernetes LabelSelector: matchLabels AND matchExpressions must both match).
cilium_endpoint_selector_matches(spec, _) if {
	count(object.get(spec.endpointSelector, "matchLabels", {})) == 0
	count(object.get(spec.endpointSelector, "matchExpressions", [])) == 0
}

# --- Workload connection checks (Deployment, ReplicaSet, DaemonSet, StatefulSet, Job) ---

# Standard NetworkPolicy with podSelector (with labels)
connected_to_network_policy(wl, networkpolicy) if {
	workload_kinds := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job"}
	workload_kinds[wl.kind]
	is_same_namespace(networkpolicy.metadata, wl.metadata)
	networkpolicy.kind == "NetworkPolicy"
	count(networkpolicy.spec.podSelector) > 0
	count({x | networkpolicy.spec.podSelector.matchLabels[x] == wl.spec.template.metadata.labels[x]}) == count(networkpolicy.spec.podSelector.matchLabels)
}

# CiliumNetworkPolicy
connected_to_network_policy(wl, networkpolicy) if {
	workload_kinds := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job"}
	workload_kinds[wl.kind]
	is_same_namespace(networkpolicy.metadata, wl.metadata)
	networkpolicy.kind == "CiliumNetworkPolicy"
	spec := cilium_policy_specs(networkpolicy)[_]
	cilium_endpoint_selector_matches(spec, object.get(wl.spec.template.metadata, "labels", {}))
}

# CiliumClusterwideNetworkPolicy (no namespace check)
connected_to_network_policy(wl, networkpolicy) if {
	workload_kinds := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job"}
	workload_kinds[wl.kind]
	networkpolicy.kind == "CiliumClusterwideNetworkPolicy"
	spec := cilium_policy_specs(networkpolicy)[_]
	cilium_endpoint_selector_matches(spec, object.get(wl.spec.template.metadata, "labels", {}))
}

# --- Pod connection checks ---

# Standard NetworkPolicy with podSelector (with labels)
connected_to_network_policy(wl, networkpolicy) if {
	wl.kind == "Pod"
	is_same_namespace(networkpolicy.metadata, wl.metadata)
	networkpolicy.kind == "NetworkPolicy"
	count(networkpolicy.spec.podSelector) > 0
	count({x | networkpolicy.spec.podSelector.matchLabels[x] == wl.metadata.labels[x]}) == count(networkpolicy.spec.podSelector.matchLabels)
}

# CiliumNetworkPolicy
connected_to_network_policy(wl, networkpolicy) if {
	wl.kind == "Pod"
	is_same_namespace(networkpolicy.metadata, wl.metadata)
	networkpolicy.kind == "CiliumNetworkPolicy"
	spec := cilium_policy_specs(networkpolicy)[_]
	cilium_endpoint_selector_matches(spec, object.get(wl.metadata, "labels", {}))
}

# CiliumClusterwideNetworkPolicy (no namespace check)
connected_to_network_policy(wl, networkpolicy) if {
	wl.kind == "Pod"
	networkpolicy.kind == "CiliumClusterwideNetworkPolicy"
	spec := cilium_policy_specs(networkpolicy)[_]
	cilium_endpoint_selector_matches(spec, object.get(wl.metadata, "labels", {}))
}

# --- CronJob connection checks ---

# Standard NetworkPolicy with podSelector (with labels)
connected_to_network_policy(wl, networkpolicy) if {
	wl.kind == "CronJob"
	is_same_namespace(networkpolicy.metadata, wl.metadata)
	networkpolicy.kind == "NetworkPolicy"
	count(networkpolicy.spec.podSelector) > 0
	count({x | networkpolicy.spec.podSelector.matchLabels[x] == wl.spec.jobTemplate.spec.template.metadata.labels[x]}) == count(networkpolicy.spec.podSelector.matchLabels)
}

# CiliumNetworkPolicy
connected_to_network_policy(wl, networkpolicy) if {
	wl.kind == "CronJob"
	is_same_namespace(networkpolicy.metadata, wl.metadata)
	networkpolicy.kind == "CiliumNetworkPolicy"
	spec := cilium_policy_specs(networkpolicy)[_]
	cilium_endpoint_selector_matches(spec, object.get(wl.spec.jobTemplate.spec.template.metadata, "labels", {}))
}

# CiliumClusterwideNetworkPolicy (no namespace check)
connected_to_network_policy(wl, networkpolicy) if {
	wl.kind == "CronJob"
	networkpolicy.kind == "CiliumClusterwideNetworkPolicy"
	spec := cilium_policy_specs(networkpolicy)[_]
	cilium_endpoint_selector_matches(spec, object.get(wl.spec.jobTemplate.spec.template.metadata, "labels", {}))
}

# --- Empty selector for standard NetworkPolicy (selects all in namespace) ---

connected_to_network_policy(wl, networkpolicy) if {
	is_same_namespace(networkpolicy.metadata, wl.metadata)
	networkpolicy.kind == "NetworkPolicy"
	count(networkpolicy.spec.podSelector) == 0
}

is_same_namespace(metadata1, metadata2) if {
	metadata1.namespace == metadata2.namespace
}

is_same_namespace(metadata1, metadata2) if {
	not metadata1.namespace
	not metadata2.namespace
}

is_same_namespace(metadata1, metadata2) if {
	not metadata2.namespace
	metadata1.namespace == "default"
}

is_same_namespace(metadata1, metadata2) if {
	not metadata1.namespace
	metadata2.namespace == "default"
}

# regal ignore:directory-package-mismatch
package armo_builtins

import rego.v1

# Checks if NodePort or LoadBalancer is connected to a workload to expose something
deny contains msga if {
	spec_template_spec_patterns := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Pod", "Job", "CronJob"}
	failPath := ["spec.type"]
	service := input[_]
	service.kind == "Service"
	is_exposed_service(service)

	wl := input[_]
	spec_template_spec_patterns[wl.kind]
	is_same_namespace(wl.metadata, service.metadata)
	pod := get_pod_spec(wl).spec
	wl_connected_to_service(pod, service)
	msga := {
		"alertMessage": sprintf("workload '%v' is exposed through service '%v'", [wl.metadata.name, service.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"fixPaths": [],
		"failedPaths": [],
		"alertObject": {"k8sApiObjects": [wl]},
		"relatedObjects": [{
			"object": service,
			"reviewPaths": failPath,
			"failedPaths": failPath,
		}],
	}
}

# Checks if Ingress is connected to a service and a workload to expose something
deny contains msga if {
	spec_template_spec_patterns := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Pod", "Job", "CronJob"}
	ingress := input[_]
	ingress.kind == "Ingress"

	svc := input[_]
	svc.kind == "Service"

	# Make sure that they belong to the same namespace
	svc.metadata.namespace == ingress.metadata.namespace

	# avoid duplicate alerts
	# if service is already exposed through NodePort or LoadBalancer workload will fail on that
	not is_exposed_service(svc)

	wl := input[_]
	spec_template_spec_patterns[wl.kind]
	is_same_namespace(wl.metadata, svc.metadata)
	wl_connected_to_service(wl, svc)

	result := svc_connected_to_ingress(svc, ingress)

	msga := {
		"alertMessage": sprintf("workload '%v' is exposed through ingress '%v'", [wl.metadata.name, ingress.metadata.name]),
		"packagename": "armo_builtins",
		"failedPaths": [],
		"fixPaths": [],
		"alertScore": 7,
		"alertObject": {"k8sApiObjects": [wl]},
		"relatedObjects": [
			{
				"object": ingress,
				"reviewPaths": result,
				"failedPaths": result,
			},
			{"object": svc},
		],
	}
}

# ====================================================================================

is_exposed_service(svc) if {
	svc.spec.type == "NodePort"
}

is_exposed_service(svc) if {
	svc.spec.type == "LoadBalancer"
}

wl_connected_to_service(wl, svc) if {
	count({x | svc.spec.selector[x] == wl.metadata.labels[x]}) == count(svc.spec.selector)
}

wl_connected_to_service(wl, svc) if {
	wl.spec.selector.matchLabels == svc.spec.selector
}

wl_connected_to_service(wl, svc) if {
	count({x | svc.spec.selector[x] == wl.spec.template.metadata.labels[x]}) == count(svc.spec.selector)
}

# check if service is connected to ingress
svc_connected_to_ingress(svc, ingress) := result if {
	result := [path |
		rule := ingress.spec.rules[i]
		paths := rule.http.paths[j]
		svc.metadata.name == paths.backend.service.name
		path := sprintf("spec.rules[%d].http.paths[%d].backend.service.name", [i, j])
	]
	count(result) > 0
}

is_same_namespace(metadata1, metadata2) if {
	metadata1.namespace == metadata2.namespace
}

is_same_namespace(metadata1, metadata2) if {
	not metadata1.namespace
	not metadata2.namespace
}

is_same_namespace(metadata1, metadata2) if {
	not metadata2.namespace
	metadata1.namespace == "default"
}

is_same_namespace(metadata1, metadata2) if {
	not metadata1.namespace
	metadata2.namespace == "default"
}

# get_volume - get resource spec paths for {"Deployment","ReplicaSet","DaemonSet","StatefulSet","Job"}
get_pod_spec(resources) := result if {
	resources_kinds := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job"}
	resources_kinds[resources.kind]
	result = {"spec": resources.spec.template, "start_of_path": "spec.template."}
}

# get_volume - get resource spec paths for "Pod"
get_pod_spec(resources) := result if {
	resources.kind == "Pod"
	result = {"spec": resources, "start_of_path": ""}
}

# get_volume - get resource spec paths for "CronJob"
get_pod_spec(resources) := result if {
	resources.kind == "CronJob"
	result = {"spec": resources.spec.jobTemplate.spec.template.spec, "start_of_path": "spec.jobTemplate.spec.template.spec."}
}

# regal ignore:directory-package-mismatch
package armo_builtins

import rego.v1

################################################################################
# Rules
deny contains msga if {
	start_of_path := "spec"
	pod := input[_]
	pod.kind == "Pod"
	container := pod.spec.containers[i]

	run_as_user_fixpath := evaluate_workload_run_as_user(container, pod, start_of_path)
	run_as_group_fixpath := evaluate_workload_run_as_group(container, pod, start_of_path)
	all_fixpaths := array.concat(run_as_user_fixpath, run_as_group_fixpath)
	count(all_fixpaths) > 0
	fixPaths := get_fixed_paths(all_fixpaths, i)

	msga := {
		"alertMessage": sprintf("container: %v in pod: %v  may run as root", [container.name, pod.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"reviewPaths": [],
		"failedPaths": [],
		"fixPaths": fixPaths,
		"alertObject": {"k8sApiObjects": [pod]},
	}
}

deny contains msga if {
	start_of_path := "spec.template.spec"
	spec_template_spec_patterns := {"Deployment", "ReplicaSet", "DaemonSet", "StatefulSet", "Job"}
	wl := input[_]
	spec_template_spec_patterns[wl.kind]
	container := wl.spec.template.spec.containers[i]

	run_as_user_fixpath := evaluate_workload_run_as_user(container, wl.spec.template, start_of_path)
	run_as_group_fixpath := evaluate_workload_run_as_group(container, wl.spec.template, start_of_path)
	all_fixpaths := array.concat(run_as_user_fixpath, run_as_group_fixpath)
	count(all_fixpaths) > 0
	fixPaths := get_fixed_paths(all_fixpaths, i)

	msga := {
		"alertMessage": sprintf("container: %v in %v: %v may run as root", [container.name, wl.kind, wl.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"reviewPaths": [],
		"failedPaths": [],
		"fixPaths": fixPaths,
		"alertObject": {"k8sApiObjects": [wl]},
	}
}

# Fails if cronjob has a container configured to run as root
deny contains msga if {
	start_of_path := "spec.jobTemplate.spec.template.spec"
	wl := input[_]
	wl.kind == "CronJob"
	container = wl.spec.jobTemplate.spec.template.spec.containers[i]

	run_as_user_fixpath := evaluate_workload_run_as_user(container, wl.spec.jobTemplate.spec.template, start_of_path)
	run_as_group_fixpath := evaluate_workload_run_as_group(container, wl.spec.jobTemplate.spec.template, start_of_path)
	all_fixpaths := array.concat(run_as_user_fixpath, run_as_group_fixpath)
	count(all_fixpaths) > 0
	fixPaths := get_fixed_paths(all_fixpaths, i)

	msga := {
		"alertMessage": sprintf("container: %v in %v: %v  may run as root", [container.name, wl.kind, wl.metadata.name]),
		"packagename": "armo_builtins",
		"alertScore": 7,
		"reviewPaths": [],
		"failedPaths": [],
		"fixPaths": fixPaths,
		"alertObject": {"k8sApiObjects": [wl]},
	}
}

get_fixed_paths(all_fixpaths, i) := [{"path": replace(all_fixpaths[0].path, "container_ndx", format_int(i, 10)), "value": all_fixpaths[0].value}, {"path": replace(all_fixpaths[1].path, "container_ndx", format_int(i, 10)), "value": all_fixpaths[1].value}] if {
	count(all_fixpaths) == 2
} else := [{"path": replace(all_fixpaths[0].path, "container_ndx", format_int(i, 10)), "value": all_fixpaths[0].value}]

#################################################################################
# Workload evaluation

# if runAsUser is set to 0 and runAsNonRoot is set to false/ not set - suggest to set runAsUser to 1000
# if runAsUser is not set and runAsNonRoot is set to false/ not set - suggest to set runAsNonRoot to true
# all checks are both on the pod and the container level
evaluate_workload_run_as_user(container, pod, start_of_path) := fixPath if {
	runAsNonRootValue := get_run_as_non_root_value(container, pod, start_of_path)
	runAsNonRootValue.value == false

	runAsUserValue := get_run_as_user_value(container, pod, start_of_path)
	runAsUserValue.value == 0

	alertInfo := choose_first_if_defined(runAsUserValue, runAsNonRootValue)
	fixPath := alertInfo.fixPath
} else := []

# if runAsGroup is set to 0/ not set - suggest to set runAsGroup to 1000
# all checks are both on the pod and the container level
evaluate_workload_run_as_group(container, pod, start_of_path) := fixPath if {
	runAsGroupValue := get_run_as_group_value(container, pod, start_of_path)
	runAsGroupValue.value == 0

	fixPath := runAsGroupValue.fixPath
} else := []

#################################################################################
# Value resolution functions

get_run_as_non_root_value(container, pod, start_of_path) := runAsNonRoot if {
